def _run_background_governed_phase(workspace_raw: str) -> int:
    executor = GovernedExecutor(DEFAULT_REPO)
    workspace = Path(workspace_raw).resolve()
    try:
        workspace.relative_to(executor.staging_root.resolve())
    except ValueError as exc:
        raise GovernedError("Background workspace escapes governed staging") from exc
    request_path = workspace / "background-request.json"
    if not request_path.is_file():
        raise GovernedError("Background request record is missing")
    request_record = load_json(request_path)
    if not isinstance(request_record, dict) or not isinstance(
        request_record.get("request"), dict
    ):
        raise GovernedError("Background request record is invalid")
    req = request_record["request"]
    job_id = executor._safe_job_id(req.get("job_id"))
    if request_record.get("job_id") != job_id:
        raise GovernedError("Background request job mismatch")

    started_at = iso_now()
    running_state = {
        "schema_version": "1.0",
        "kind": "governed_phase_background",
        "job_id": job_id,
        "run_id": workspace.name,
        "status": "running",
        "request_sha256": request_record.get("request_sha256"),
        "worker_pid": os.getpid(),
        "started_at": started_at,
        "updated_at": started_at,
    }
    atomic_write_json(workspace / "run-state.json", running_state)

    try:
        result = executor.run_governed_phase(req)
        atomic_write_json(workspace / "phase-result.json", result)
        terminal_status = "completed" if bool(result.get("ok")) else "failed"
        final_state = {
            **running_state,
            "status": terminal_status,
            "updated_at": iso_now(),
            "completed_at": iso_now(),
            "ok": bool(result.get("ok")),
            "summary": result.get("summary"),
            "candidate_run_id": result.get("run_id"),
            "result_path": str(
                (workspace / "phase-result.json").relative_to(executor.repo)
            ),
        }
        atomic_write_json(workspace / "run-state.json", final_state)
        return 0 if bool(result.get("ok")) else 1
    except Exception as exc:
        error_record = {
            "schema_version": "1.0",
            "job_id": job_id,
            "run_id": workspace.name,
            "failed_at": iso_now(),
            "error_type": type(exc).__name__,
            "error": str(exc),
        }
        atomic_write_json(workspace / "phase-error.json", error_record)
        failed_state = {
            **running_state,
            "status": "failed",
            "updated_at": iso_now(),
            "completed_at": iso_now(),
            "ok": False,
            "error_type": type(exc).__name__,
            "error": str(exc),
            "error_path": str(
                (workspace / "phase-error.json").relative_to(executor.repo)
            ),
        }
        atomic_write_json(workspace / "run-state.json", failed_state)
        return 1


def _executor_cli_main() -> int:
    if len(sys.argv) == 3 and sys.argv[1] == "--background-governed-phase":
        try:
            return _run_background_governed_phase(sys.argv[2])
        except Exception as exc:
            print(
                json.dumps(
                    {
                        "ok": False,
                        "error_type": type(exc).__name__,
                        "error": str(exc),
                    },
                    ensure_ascii=False,
                    sort_keys=True,
                ),
                file=sys.stderr,
            )
            return 1
    return 0


if __name__ == "__main__":
    raise SystemExit(_executor_cli_main())

