    def _active_background_phase(self, job_id: str) -> dict[str, Any] | None:
        root = self._background_root(job_id)
        if not root.is_dir():
            return None
        for workspace in sorted(
            (p for p in root.iterdir() if p.is_dir()),
            key=lambda p: p.name,
            reverse=True,
        ):
            state_path = workspace / "run-state.json"
            if not state_path.is_file():
                continue
            try:
                state = load_json(state_path)
            except Exception:
                continue
            if not (
                isinstance(state, dict)
                and state.get("kind") == "governed_phase_background"
                and state.get("status") in {"queued", "running"}
            ):
                continue

            pid = state.get("worker_pid")
            if not isinstance(pid, int):
                pid_path = workspace / "worker-pid.json"
                if pid_path.is_file():
                    with contextlib.suppress(Exception):
                        pid_record = load_json(pid_path)
                        if isinstance(pid_record, dict):
                            pid = pid_record.get("worker_pid")
            alive = self._worker_alive(pid)
            if alive is False:
                failed_state = {
                    **state,
                    "status": "failed",
                    "stage": "worker_liveness",
                    "updated_at": iso_now(),
                    "completed_at": iso_now(),
                    "ok": False,
                    "error_type": "WorkerExited",
                    "error": "Background worker exited without a terminal run state",
                }
                atomic_write_json(state_path, failed_state)
                continue
            return {
                "workspace": workspace,
                "state": state,
            }
        return None

