    def _worker_alive(self, pid: Any) -> bool | None:
        if not isinstance(pid, int) or pid <= 0:
            return None
        try:
            os.kill(pid, 0)
        except ProcessLookupError:
            return False
        except PermissionError:
            return True
        return True

    def _background_root(self, job_id: str) -> Path:
        return self.staging_root / job_id / "_background"

    def _background_workspace(
        self,
        job_id: str,
        run_id: str | None = None,
        *,
        create: bool = False,
    ) -> Path:
        rid = run_id or f"bg-{utc_stamp()}-{uuid.uuid4().hex[:8]}"
        if not re.fullmatch(r"[A-Za-z0-9._-]+", rid):
            raise GovernedError("Invalid background run_id")
        workspace = self._background_root(job_id) / rid
        if create:
            workspace.mkdir(parents=True, exist_ok=False)
        return workspace
